	"com/cytechies/integration/reliability/incidentclustersui/i18n/i18n.properties":'# This is the resource bundle for com.cytechies.integration.reliability.incidentclustersui\n\n#Texts for manifest.json\n\n#XTIT: Application name\nappTitle=Integration Reliability Dashboard\n\n#YDES: Application description\nappDescription=SAP Fiori application for monitoring integration incidents and reliability analytics.\n#XTIT: Main view title\ntitle=Integration Reliability Dashboard\n\n\n\n\n\n#Chat view\n# \\u2500\\u2500 Navigation \\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\nbackButton.tooltip=Navigate back\nnewChat.tooltip=New Chat\nchatHistory.tooltip=Chat History\n\n# \\u2500\\u2500 Page Header \\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\ntoolHeader.title=AI Chat \\u2726 Grounded on live HANA data\nchat.header.newChat=New Chat\nchat.header.tokens={0} Tokens\nchat.header.noTokens=No Tokens\nchat.header.deleteTooltip=Delete Chat\n\n# \\u2500\\u2500 Welcome Page \\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\nwelcome.avatar.tooltip=Integration Reliability Agent\nwelcome.title=Welcome to Integration Reliability Agent\nwelcome.subtitle=Your intelligent assistant for live integration data in SAP HANA. Ask a question below to analyze errors, patterns, and remediation steps.\nwelcome.suggestions.label=Try asking:\nwelcome.suggestion.s1=How do I troubleshoot a failing iFlow?\nwelcome.suggestion.s2=How to configure retry mechanisms safely\nwelcome.suggestion.s3=Explain split and gather routing logic\nwelcome.suggestion.s4=What is an incident cluster?\nwelcome.suggestion.s5=How to analyze an XML parsing failure\nwelcome.suggestion.s6=Common remediation steps for HTTP 500 errors\n\n# \\u2500\\u2500 Chat History Popover \\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\nhistory.popover.title=Chat History\n\n# \\u2500\\u2500 Data History Popover \\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\nremove.popover.cluster.button=Remove Cluster\nactionDataPopover.cluster.button=Attach Cluster Data\nactiveClusterPopover.title=Attached Cluster\nclusterPopover.title=Incident Clusters\nhistory.search.placeholder=Search by ChatSessions...\n\n\n\nremove.popover.iflow.button=Remove iFlow\nactionDataPopover.iflow.button=Attach iFlow Data\nactiveiFlowPopover.title=Attached iFlow\niFlowPopover.title=Monitored iFlows\n\n# \\u2500\\u2500 Footer / Input Area \\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\ncluster.toggle.attach.tooltip=Click to attach Incident Cluster Data.\ncluster.toggle.detach.tooltip=Incident context active \\u2014 click to detach.\ninput.placeholder.default=Ask about errors, clusters, flows, or remediation... (Shift+Enter for new line)\ninput.placeholder.clusterActive=\\ud83d\\udcce Cluster attached \\u2014 ask anything...\nsend.button.tooltip=Send (Enter)\n\n# \\u2500\\u2500 Toast / Error Messages \\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\ntoast.error.loadHistory=Error loading conversation history.\ntoast.error.createConversation=Failed to create conversation\ntoast.error.chat=Sorry, I encountered an error processing your request.\ntoast.error.deleteConversation=Failed to delete conversation.\n\n# \\u2500\\u2500 Token Display \\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\ntokens.calculating=Calculating...\ntokens.none=No Tokens\ntokens.count={0} Tokens\n\n#XFLD,87\nIRAgent-monitor.flpTitle=Integration Reliability Agent\n\n#XFLD,88.5\nIRAgent-monitor.flpSubtitle=Monitor iFlows, error clusters, and integration statistics.\n',
